 1	@value kialiFontSize: 14px;
 2	@value kialiFontSizePx: 14;
 3	
 4	.style {
 5	  // Set global base font size to 14px per current OpenShift design
 6	  // https://github.com/openshift/console/blob/ef1212655ba60571aaeec666843cd9f1ef139189/frontend/public/style/_vars.scss#L16
 7	  $font-size-base: kialiFontSize;
 8	
 9	  /**
10	   * Define --kiali-global--font-size to match $font-size-base.
11	   * It should be used across kiali as the default fontSize, unless the case is exceptional.
12	   * We then override --pf-t--global--font--size--md to be our kiali default. This is a widely
13	   * used PF default font size (typically 16px), but we want it smaller in Kiali, for
14	   * consistency and space efficiency (and to echo console).
15	   */
16	  --kiali-global--font-size: kialiFontSize;
17	  --kiali-global--font-size-px: kialiFontSizePx;
18	  --pf-t--global--font--size--md: kialiFontSize;
19	
20	  /**
21	    * --pf-v6-c-page__header--MinHeight is the height of the masthead
22	    * 130px is the vertical space being used by the breadcrumb, tab headers, and the name of the {workload,svc,app}
23	    */
24	  --kiali-details-pages-tab-content-height: calc(100vh - 130px - var(--pf-v6-c-page__header--MinHeight));
25	
26	  // Graph CSS variables
27	  --graph-side-panel--font-size: kialiFontSize;
28	  --graph-side-panel--font-size-px: kialiFontSizePx;
29	
30	  :global {
31	    /**
32	    * --pf-v6-c-page__header--MinHeight is the height of the masthead
33	    * 130px is the vertical space being used by the breadcrumb, tab headers, and the name of the {workload,svc,app}
34	    */
35	    .pf-v6-c-page__main-section {
36	      --kiali-details-pages-tab-content-height: calc(100vh - 130px - var(--pf-v6-c-page__header--MinHeight));
37	    }
38	
39	    /**
40	     * Then, in components for which we don't want the override, we must
41	     * revert the change back to the desired font size.
42	     */
43	    .pf-v6-c-nav__link {
44	      --pf-v6-c-nav__link--FontSize: 16px;
45	    }
46	
47	    .pf-v6-c-tabs__link {
48	      --pf-v6-c-tabs__link--FontSize: 16px;
49	    }
50	
51	    /**
52	     * Ensure Chips and ChipGroups show long values
53	     */
54	    .pf-v5-c-chip-group__label {
55	      --pf-v6-c-chip-group__label--MaxWidth: 50em;
56	    }
57	
58	    .pf-v5-c-chip__text {
59	      --pf-v6-c-chip__text--MaxWidth: 50em;
60	    }
61	  }
62	}

